var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"사, 사무직으로 지원한 김철수입니다! 귀사의 무궁한……","JPN":"じ、事務職で応募したタナカ・ジロウです！　御社の限りなき繁栄を……","ENG":"H-hello! I'm Kim Chulsoo. I've applied for a desk job! I wish your company prosperity and–","TWN":"我…我是應徵文書一職的金哲洙！貴公司的……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"됐고. 김철수 씨. 지금 나랑 장난하자는 겁니까?","JPN":"もういいです。タナカ・ジロウさん。ふざけてるんですか？","ENG":"Cut the slack, Mr. Kim Chulsoo. What do you think you’re doing?","TWN":"夠了，金哲洙先生，你是在跟我開玩笑嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"예?","JPN":"はい？","ENG":"Excuse me?","TWN":"什麼？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"면접에 지각한 것부터가 결격 사유인데, 꼴이 그게 뭡니까?","JPN":"面接に遅刻してすでにイメージが悪いのに、その格好は何ですか？","ENG":"Being late to an interview is already a big minus, but that attire?","TWN":"光是面試遲到就足以構成落選的原因，再看看你那是什麼德性？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"정장 단추 좀 잠그세요! 어디서 이종 격투기라도 몇 라운드 구르고 오셨나보죠?","JPN":"スーツのボタンも取れてだらしない！　どこかで総合格闘技でもやってきたのですか？","ENG":"Button up your suit! Where were you, at a boxing ring or something?","TWN":"拜託把襯衫的釦子扣好吧！你是剛去參加完格鬥賽才過來的嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"헛!? 이, 이게…… 단추가 언제 떨어졌지?","JPN":"はっ！？　こ、これは……いつの間にボタンが？","ENG":"Ah?! O-oh... I didn’t know it fell off...","TWN":"唔！？這……釦子是什麼時候鬆開的？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"당신 경력이 어떻든, 우리 회사에 기본 매너도 안 된 사람은 필요 없습니다.","JPN":"あなたの経歴がどうであれ、この会社に基本的なマナーもなってない人は必要ありません。","ENG":"I don’t care how experienced you are, we do not take in any ill-mannered individuals in this company.","TWN":"就算你的履歷再好，我們公司也不會要一個連基本禮貌都不懂的人。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"면접비는 드릴 테니까, 가는 길에 세탁소 들려서 단추나 달고 가시죠.","JPN":"交通費は差し上げますから、帰りにクリーニング屋に寄ってボタンでも付けてもらってください。","ENG":"You will be compensated for attending the interview. Go get yourself some new buttons or something.","TWN":"我會給你一些車馬費，你回去的時候找間服飾店把扣子補上吧！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SECRETARY_NPC_ALPHA_NULL","text":{"KOREA":"자, 잠시만요, 이사님! 드릴 말씀이……!","JPN":"ま、待ってください、専務！　お話が……！","ENG":"W-wait, sir! There’s something you need to know...!","TWN":"那…那個，理事！我有話……！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"아이고…… 이렇게 유명하신 분을 몰라뵙고…….","JPN":"おっと……こんな有名な方を……","ENG":"Goodness... I should have recognized a hero like you...","TWN":"哎呀呀……我真是有眼不識泰山……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"성함이 워낙 흔하셔서 그만 제가 실수를 범했지 뭡니까. 지원자님.","JPN":"あまりにもありふれたお名前でしたので、うっかり失礼なことをしてしまいましたね。タナカさん。","ENG":"Your name was rather common, which led me to mistake you for someone else. Forgive me, Mr. Kim.","TWN":"因為您的名字太菜市場，我才會一時不察犯下大錯。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"하, 하하……. 아닙니다.","JPN":"は、はは……いいえ。","ENG":"Hah... hah hah... No worries.","TWN":"哈，哈哈……別這麼說。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"몇 년 전, 역삼동에서 발생했던 침식 재난에서 활약하셨다고요?","JPN":"何年か前に、ベルタ町で発生した侵食災害の時にご活躍なさったと。","ENG":"I hear you were there at the Corruption disaster in Yeoksam, back a few years ago.","TWN":"聽說您曾經參與過幾年前在驛三洞發生的侵蝕災難嗎？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그 언론에서도 꽤 크게 다루지 않습니까? 뭐더라? 아! 역삼동이 낳은 전설의 파이터!","JPN":"メディアでも結構大きく取りあげていましたよね。何でしたっけ？　あ！　ベルタ町が産んだ伝説のファイター！","ENG":"It was all over the news, wasn’t it? What was the title again? Oh! \\"Yeoksam’s Legendary Fighter!\\"","TWN":"那時候媒體也是大肆報導呢，說什麼？喔！驛三洞誕生的勇者傳說！"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"하하, 그런 경험을 이력서에 적어주셨으면 서로 편했을 텐데요.","JPN":"はは、そういう経験を履歴書に書いていただいたら、お互い誤解しなかったでしょうに。","ENG":"Ha ha. It would've been convenient for both of us if you wrote it down on your resume.","TWN":"哈哈，這麼精彩的經歷應該要寫在履歷表上才對嘛，這樣我們彼此也比較省事。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERVIEWER_NPC_GAMECIRCLE_NULL","text":{"KOREA":"뭐, 좋습니다. 제가 초면에 실례도 했으니 대신 괜찮은 일자리를 하나 주선해드리죠.","JPN":"ま、いいでしょう。私が初対面にもかかわらず失礼をしたので、そのお詫びとしていい仕事をご紹介しましょう。","ENG":"Well, it doesn’t matter anymore. To make up for my discourtesy, I will offer you an even better job.","TWN":"好吧！雖然我一開始有點失禮，但我會替您安排一個好位子的。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"INTERVIEWER_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};